import classNames from "classnames";
import { useState } from "react";
import { FieldRenderProps } from "react-final-form";

import styles from "./password-field-styles.module.scss";

interface IProps extends FieldRenderProps<string, HTMLInputElement> {
  className: string;
  // isSubmitError?: string | number | undefined;
}

export const PasswordField: React.FC<IProps> = ({ input, className }) => {
  const [isShowPassword, setIsShowPassword] = useState(false);

  const togglePassword = () => {
    setIsShowPassword(!isShowPassword);
  };

  return (
    <div className={styles["input-container"]}>
      <input
        {...input}
        className={className}
        type={isShowPassword ? "text" : "password"}
        placeholder="Пароль"
      />
      <button
        className={classNames(styles["toggle-btn"])}
        type="button"
        onClick={togglePassword}
      // hidden={Boolean(isSubmitError)}
      />
    </div>
  );
}