import { useCallback } from "react";
import { useNavigate } from 'react-router-dom';
import { useSignIn } from "react-auth-kit";
import qs from "qs";
import axios, { AxiosError } from "axios";
import { FORM_ERROR } from 'final-form'

import { END_POINTS } from "@/services/endpoints";

import { AuthForm } from "./auth-form";
import { FORM_ERROR_TEXT } from "./auth-form-constants";

export const AuthFormController = () => {
  const navigate = useNavigate();
  const signIn = useSignIn();

  const auth = async (values: any) => {
    const data = qs.stringify({
      'client_id': 'lenta-app',
      'username': values.username,
      'password': String(values.password),
      'grant_type': 'password',
    });

    const config = {
      method: 'post',
      url: END_POINTS.auth.path,
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      data: data
    };

    try {
      const { data }: any = await axios(config);

      signIn({
        token: data.access_token,
        expiresIn: data.expires_in,
        tokenType: "Bearer",
        // refreshToken: data.refreshToken,                    // Only if you are using refreshToken feature
        // refreshTokenExpireIn: data.refresh_expires_in
      });

      navigate("/qr-scan");
    } catch (err) {
      if (err instanceof AxiosError) {
        return { [FORM_ERROR]: FORM_ERROR_TEXT };
      } else if (err instanceof Error) {
        return err.message;
      }
    }

  };

  const onSubmit = useCallback(
    (values: any) => auth(values),
    [],
  );

  return <AuthForm onSubmit={onSubmit} />
};
