import { RequireAuth } from "react-auth-kit";

import { AuthPage } from "@/pages/auth-page";
import { QrScanPage } from "@/pages/qr-scan-page";

export type RouterDescriptor = {
  path: string;
  element: any;
};

export const routes: RouterDescriptor[] = [
  {
    path: "/",
    element: <AuthPage />,
  },
  {
    path: "/qr-scan",
    element: <RequireAuth loginPath={'/'}><QrScanPage /></RequireAuth>
  }
];
